        @for (int i = 0; i < steps.Length; i++)
        {
            var stepNum = i + 1;
            var isCompleted = CompletedSteps.Contains(stepNum);
            var isCurrent = stepNum == CurrentStep;
            var isClickable = isCompleted && !isCurrent;

            <div class="text-center flex-fill position-relative">
                <button type="button"
                        class="btn rounded-circle d-inline-flex align-items-center justify-content-center @StepBtnClass(stepNum, isCurrent, isCompleted)"
                        style="width:36px; height:36px; font-size:0.85rem;"
                        disabled="@(!isClickable)"
                        @onclick="() => OnStepClicked.InvokeAsync(stepNum)">
                    @if (isCompleted && !isCurrent)
                    {
                        <span>✓</span>
                    }
                    else
                    {
                        @stepNum
                    }
                </button>
                <div class="small mt-1 @(isCurrent ? "fw-bold" : isCompleted ? "" : "text-muted")">
                    @steps[i]
                </div>
            </div>

            @if (i < steps.Length - 1)
            {
                <div class="flex-fill align-self-start" style="margin-top:18px;">
                    <hr class="@(CompletedSteps.Contains(stepNum) ? "border-primary" : "border-secondary")" />
                </div>
            }
        }
    </div>
</nav>

