@page "/apply"
@rendermode InteractiveServer
@using sv_2f2fb9b81f1948d7bcf7d26dcf565ed8.Models
@using sv_2f2fb9b81f1948d7bcf7d26dcf565ed8.Services
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<h2 class="mb-4">Job Application</h2>

@if (_submitted)
{
    <div class="alert alert-success text-center p-5">
        <h3>🎉 Application Submitted!</h3>
        <p class="lead mt-3">Your application has been received.</p>
        <p>Application ID: <strong>@_applicationId</strong></p>
        <button class="btn btn-primary mt-3" @onclick="ResetForm">Submit Another Application</button>
    </div>
}
else
{
    <StepIndicator CurrentStep="_currentStep"
                   CompletedSteps="_completedSteps"
                   OnStepClicked="GoToStep" />

    <div class="card mt-4">
        <div class="card-body">
            @switch (_currentStep)
            {
                case 1:
                    <StepPersonalInfo FullName="@_fullName" Email="@_email" Phone="@_phone" Address="@_address"
                                      FullNameChanged="v => _fullName = v"
                                      EmailChanged="v => _email = v"
                                      PhoneChanged="v => _phone = v"
                                      AddressChanged="v => _address = v"
                                      ValidationErrors="_validationErrors"
                                      OnNext="HandlePersonalInfoNext" />
                    break;

                case 2:
                    <StepWorkHistory WorkEntries="_workEntries"
                                     CurrentFlags="_currentJobFlags"
                                     ValidationErrors="_validationErrors"
                                     OnBack="() => GoToStep(1)"
                                     OnNext="HandleWorkHistoryNext" />
                    break;

                case 3:
                    <StepReferences References="_references"
                                    ValidationErrors="_validationErrors"
                                    OnBack="() => GoToStep(2)"
                                    OnNext="HandleReferencesNext" />
                    break;

                case 4:
                    <StepCoverLetter CoverLetter="@_coverLetter"
                                     CoverLetterChanged="v => _coverLetter = v"
                                     MaxLength="2000"
                                     OnBack="() => GoToStep(3)"
                                     OnNext="HandleCoverLetterNext" />
                    break;

                case 5:
                    <StepReview FullName="@_fullName" Email="@_email" Phone="@_phone" Address="@_address"
                                WorkEntries="_workEntries" CurrentFlags="_currentJobFlags"
                                References="_references" CoverLetter="@_coverLetter"
                                IsSubmitting="_isSubmitting" SubmitError="@_submitError"
                                OnEdit="GoToStep"
                                OnBack="() => GoToStep(4)"
                                OnSubmit="HandleSubmit" />
                    break;
            }
        </div>
    </div>
}

@code {
    private int _currentStep = 1;
    private HashSet<int> _completedSteps = new();
    private List<string> _validationErrors = new();

    // Step 1
    private string _fullName = "";
    private string _email = "";
    private string _phone = "";
    private string _address = "";

    // Step 2
    private List<WorkEntryModel> _workEntries = new() { new WorkEntryModel() };
    private List<bool> _currentJobFlags = new() { false };

    // Step 3
    private List<ReferenceModel> _references = new() { new ReferenceModel(), new ReferenceModel() };

    // Step 4
    private string _coverLetter = "";

    // Step 5
    private bool _isSubmitting;
    private bool _submitted;
    private int _applicationId;
    private string? _submitError;

    private void GoToStep(int step)
    {
        if (step < _currentStep || _completedSteps.Contains(step) || step == _currentStep)
        {
            _validationErrors.Clear();
            _currentStep = step;
        }
    }

    private async Task HandlePersonalInfoNext()
    {
        _validationErrors.Clear();

        if (string.IsNullOrWhiteSpace(_fullName))
            _validationErrors.Add("Full name is required.");
        if (string.IsNullOrWhiteSpace(_email))
            _validationErrors.Add("Email is required.");
        if (string.IsNullOrWhiteSpace(_phone))
            _validationErrors.Add("Phone number is required.");
        if (string.IsNullOrWhiteSpace(_address))
            _validationErrors.Add("Address is required.");

        if (_validationErrors.Count > 0) return;

        var emailValid = await ApplicationService.ValidateEmailAsync(_email);
        if (!emailValid)
        {
            _validationErrors.Add("Please enter a valid email address.");
            return;
        }

        _completedSteps.Add(1);
        _currentStep = 2;
    }

    private void HandleWorkHistoryNext()
    {
        _validationErrors.Clear();

        for (int i = 0; i < _workEntries.Count; i++)
        {
            var e = _workEntries[i];
            if (string.IsNullOrWhiteSpace(e.Company))
                _validationErrors.Add($"Entry {i + 1}: Company name is required.");
            if (string.IsNullOrWhiteSpace(e.Title))
                _validationErrors.Add($"Entry {i + 1}: Job title is required.");
            if (e.StartDate == default)
                _validationErrors.Add($"Entry {i + 1}: Start date is required.");
        }

        if (_validationErrors.Count > 0) return;

        _completedSteps.Add(2);
        _currentStep = 3;
    }

    private void HandleReferencesNext()
    {
        _validationErrors.Clear();

        for (int i = 0; i < _references.Count; i++)
        {
            var r = _references[i];
            if (string.IsNullOrWhiteSpace(r.Name))
                _validationErrors.Add($"Reference {i + 1}: Name is required.");
            if (string.IsNullOrWhiteSpace(r.Relationship))
                _validationErrors.Add($"Reference {i + 1}: Relationship is required.");
            if (string.IsNullOrWhiteSpace(r.Email))
                _validationErrors.Add($"Reference {i + 1}: Email is required.");
            if (string.IsNullOrWhiteSpace(r.Phone))
                _validationErrors.Add($"Reference {i + 1}: Phone is required.");
        }

        if (_validationErrors.Count > 0) return;

        _completedSteps.Add(3);
        _currentStep = 4;
    }

    private void HandleCoverLetterNext()
    {
        _validationErrors.Clear();

        if (string.IsNullOrWhiteSpace(_coverLetter))
            _validationErrors.Add("Cover letter is required.");
        else if (_coverLetter.Length > 2000)
            _validationErrors.Add("Cover letter must be 2000 characters or fewer.");

        if (_validationErrors.Count > 0) return;

        _completedSteps.Add(4);
        _currentStep = 5;
    }

    private async Task HandleSubmit()
    {
        _isSubmitting = true;
        _submitError = null;
        StateHasChanged();

        try
        {
            var personal = new PersonalInfo(_fullName, _email, _phone, _address);
            var workHistory = new WorkHistory(_workEntries.Select((e, i) =>
                new WorkEntry(e.Company, e.Title, e.StartDate,
                    _currentJobFlags[i] ? null : e.EndDate,
                    e.Description)).ToList());
            var refs = _references.Select(r =>
                new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList();

            var application = new JobApplication(personal, workHistory, refs, _coverLetter);
            _applicationId = await ApplicationService.SubmitApplicationAsync(application);
            _completedSteps.Add(5);
            _submitted = true;
        }
        catch (Exception ex)
        {
            _submitError = $"Submission failed: {ex.Message}";
        }
        finally
        {
