@using static sv_2f2fb9b81f1948d7bcf7d26dcf565ed8.Components.Pages.Apply.Apply

<h4>Work History</h4>

@if (ValidationErrors.Count > 0)
{
    <div class="alert alert-danger">
        <ul class="mb-0">
            @foreach (var err in ValidationErrors)
            {
                <li>@err</li>
            }
        </ul>
    </div>
}

@for (int idx = 0; idx < WorkEntries.Count; idx++)
{
    var i = idx;
    var entry = WorkEntries[i];

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="mb-0">Position @(i + 1)</h6>
                @if (WorkEntries.Count > 1)
                {
                    <button type="button" class="btn btn-sm btn-outline-danger" @onclick="() => RemoveEntry(i)">Remove</button>
                }
            </div>

            <div class="row mb-2">
                <div class="col-md-6">
                    <label class="form-label">Company Name <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" value="@entry.Company"
                           @oninput="e => entry.Company = e.Value?.ToString() ?? """ />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Job Title <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" value="@entry.Title"
                           @oninput="e => entry.Title = e.Value?.ToString() ?? """ />
                </div>
            </div>

            <div class="row mb-2">
                <div class="col-md-4">
                    <label class="form-label">Start Date <span class="text-danger">*</span></label>
                    <input type="date" class="form-control" value="@FormatDate(entry.StartDate)"
                           @onchange="e => entry.StartDate = ParseDate(e.Value?.ToString())" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">End Date</label>
                    <input type="date" class="form-control" value="@FormatDate(entry.EndDate)"
                           disabled="@CurrentFlags[i]"
                           @onchange="e => entry.EndDate = ParseNullableDate(e.Value?.ToString())" />
                </div>
                <div class="col-md-4 d-flex align-items-end mb-1">
                    <div class="form-check">
                        <input type="checkbox" class="form-check-input" id="@($"current-{i}")"
                               checked="@CurrentFlags[i]"
                               @onchange="e => ToggleCurrent(i, (bool)(e.Value ?? false))" />
                        <label class="form-check-label" for="@($"current-{i}")">Currently working here</label>
                    </div>
                </div>
            </div>

            <div class="mb-2">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="2"
                          @oninput="e => entry.Description = e.Value?.ToString() ?? """>@entry.Description</textarea>
            </div>
        </div>
    </div>
}

<button type="button" class="btn btn-outline-primary mb-3" @onclick="AddEntry">+ Add Another Position</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">← Back</button>
    <button class="btn btn-primary" @onclick="OnNext">Next →</button>
</div>

@code {
    [Parameter] public List<WorkEntryModel> WorkEntries { get; set; } = new();
    [Parameter] public List<bool> CurrentFlags { get; set; } = new();
    [Parameter] public List<string> ValidationErrors { get; set; } = new();
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }

    private void AddEntry()
    {
        WorkEntries.Add(new WorkEntryModel());
        CurrentFlags.Add(false);
    }

    private void RemoveEntry(int index)
    {
        WorkEntries.RemoveAt(index);
        CurrentFlags.RemoveAt(index);
    }

    private void ToggleCurrent(int index, bool value)
    {
        CurrentFlags[index] = value;
        if (value) WorkEntries[index].EndDate = null;
    }

    private string FormatDate(DateTime date) =>
        date == default ? "" : date.ToString("yyyy-MM-dd");

    private string FormatDate(DateTime? date) =>
        date?.ToString("yyyy-MM-dd") ?? "";

    private DateTime ParseDate(string? value) =>
        DateTime.TryParse(value, out var d) ? d : default;

    private DateTime? ParseNullableDate(string? value) =>
        DateTime.TryParse(value, out var d) ? d : null;
}

@using static sv_2f2fb9b81f1948d7bcf7d26dcf565ed8.Components.Pages.Apply.Apply

<h4>References</h4>

@if (ValidationErrors.Count > 0)
{
    <div class="alert alert-danger">
        <ul class="mb-0">
            @foreach (var err in ValidationErrors)
            {
                <li>@err</li>
            }
        </ul>
    </div>
}

@for (int idx = 0; idx < References.Count; idx++)
{
    var i = idx;
    var r = References[i];

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="mb-0">Reference @(i + 1)</h6>
                @if (References.Count > 2)
                {
                    <button type="button" class="btn btn-sm btn-outline-danger" @onclick="() => RemoveReference(i)">Remove</button>
                }
            </div>

            <div class="row mb-2">
                <div class="col-md-6">
                    <label class="form-label">Name <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" value="@r.Name"
                           @oninput="e => r.Name = e.Value?.ToString() ?? """ />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Relationship <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" value="@r.Relationship"
                           @oninput="e => r.Relationship = e.Value?.ToString() ?? """ />
                </div>
            </div>

            <div class="row mb-2">
                <div class="col-md-6">
                    <label class="form-label">Email <span class="text-danger">*</span></label>
                    <input type="email" class="form-control" value="@r.Email"
                           @oninput="e => r.Email = e.Value?.ToString() ?? """ />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Phone <span class="text-danger">*</span></label>
                    <input type="tel" class="form-control" value="@r.Phone"
                           @oninput="e => r.Phone = e.Value?.ToString() ?? """ />
                </div>
            </div>
        </div>
    </div>
}

@if (References.Count < 3)
{
    <button type="button" class="btn btn-outline-primary mb-3" @onclick="AddReference">+ Add Reference</button>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">← Back</button>
    <button class="btn btn-primary" @onclick="OnNext">Next →</button>
</div>

@code {
    [Parameter] public List<ReferenceModel> References { get; set; } = new();
    [Parameter] public List<string> ValidationErrors { get; set; } = new();
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }

    private void AddReference()
    {
        if (References.Count < 3)
            References.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
            References.RemoveAt(index);
    }
}

