toolArgs.file_text:
@using static sv_2f2fb9b81f1948d7bcf7d26dcf565ed8.Components.Pages.Apply.Apply

<h4>Review & Submit</h4>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Personal Information</strong>
        <button class="btn btn-sm btn-link" @onclick='() => OnEdit.InvokeAsync(1)'>Edit</button>
    </div>
    <div class="card-body">
        <dl class="row mb-0">
            <dt class="col-sm-3">Full Name</dt>
            <dd class="col-sm-9">@FullName</dd>
            <dt class="col-sm-3">Email</dt>
            <dd class="col-sm-9">@Email</dd>
            <dt class="col-sm-3">Phone</dt>
            <dd class="col-sm-9">@Phone</dd>
            <dt class="col-sm-3">Address</dt>
            <dd class="col-sm-9">@Address</dd>
        </dl>
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Work History</strong>
        <button class="btn btn-sm btn-link" @onclick='() => OnEdit.InvokeAsync(2)'>Edit</button>
    </div>
    <div class="card-body">
        @foreach (var (entry, i) in WorkEntries.Select((e, i) => (e, i)))
        {
            @if (i > 0) { <hr /> }
            <dl class="row mb-0">
                <dt class="col-sm-3">Company</dt>
                <dd class="col-sm-9">@entry.Company</dd>
                <dt class="col-sm-3">Title</dt>
                <dd class="col-sm-9">@entry.Title</dd>
                <dt class="col-sm-3">Period</dt>
                <dd class="col-sm-9">
                    @entry.StartDate.ToString("MMM yyyy") –
                    @(CurrentFlags[i] ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                </dd>
                @if (!string.IsNullOrWhiteSpace(entry.Description))
                {
                    <dt class="col-sm-3">Description</dt>
                    <dd class="col-sm-9">@entry.Description</dd>
                }
            </dl>
        }
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>References</strong>
        <button class="btn btn-sm btn-link" @onclick='() => OnEdit.InvokeAsync(3)'>Edit</button>
    </div>
    <div class="card-body">
        @foreach (var (r, i) in References.Select((r, i) => (r, i)))
        {
            @if (i > 0) { <hr /> }
            <dl class="row mb-0">
                <dt class="col-sm-3">Name</dt>
                <dd class="col-sm-9">@r.Name</dd>
                <dt class="col-sm-3">Relationship</dt>
                <dd class="col-sm-9">@r.Relationship</dd>
                <dt class="col-sm-3">Email</dt>
                <dd class="col-sm-9">@r.Email</dd>
                <dt class="col-sm-3">Phone</dt>
                <dd class="col-sm-9">@r.Phone</dd>
            </dl>
        }
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Cover Letter</strong>
        <button class="btn btn-sm btn-link" @onclick='() => OnEdit.InvokeAsync(4)'>Edit</button>
    </div>
    <div class="card-body">
        <p style="white-space: pre-wrap;">@CoverLetter</p>
    </div>
</div>

@if (!string.IsNullOrEmpty(SubmitError))
{
    <div class="alert alert-danger">@SubmitError</div>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">← Back</button>
    <button class="btn btn-success btn-lg" @onclick="OnSubmit" disabled="@IsSubmitting">
        @if (IsSubmitting)
        {
            <span class="spinner-border spinner-border-sm me-2" role="status"></span>
            <span>Submitting…</span>
        }
        else
        {
            <span>Submit Application</span>
        }
    </button>
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public string Address { get; set; } = "";
    [Parameter] public List<WorkEntryModel> WorkEntries { get; set; } = new();
    [Parameter] public List<bool> CurrentFlags { get; set; } = new();
    [Parameter] public List<ReferenceModel> References { get; set; } = new();
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public bool IsSubmitting { get; set; }
    [Parameter] public string? SubmitError { get; set; }
    [Parameter] public EventCallback<int> OnEdit { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }
}
